os.makedirs(r'C:\kiro\automindai\backend\media\portfolio', exist_ok=True)

for portfolio in Portfolio.objects.all():
    svg_content = PF_SVGS.get(portfolio.id)
    if not svg_content:
        print(f'No SVG for portfolio id={portfolio.id} ({portfolio.title})')
        continue

    buf = io.BytesIO(svg_content.encode('utf-8'))
    filename = f'portfolio-{portfolio.id}.svg'
    portfolio.image.save(filename, ContentFile(buf.read()), save=True)
    print(f'Saved: {portfolio.title} -> {filename}')

print('All portfolio images done!')
